-      snapshot.issues.length > 0
-        ? snapshot.issues
-            .map((issue) => `- ${issue.path}: ${issue.message}`)
-            .join("\n")
-        : "Unknown validation issue.";
-    runtime.error(`Config invalid:\n${issues}`);
