-function toModelRow(params: {
-  model?: Model<Api>;
-  key: string;
-  tags: string[];
-  aliases?: string[];
-  availableKeys?: Set<string>;
-  cfg?: ClawdbotConfig;
-  authStore?: AuthProfileStore;
-}): ModelRow {
-  const {
-    model,
-    key,
-    tags,
-    aliases = [],
-    availableKeys,
-    cfg,
-    authStore,
-  } = params;
-  if (!model) {
-    return {
-      key,
-      name: key,
-      input: "-",
-      contextWindow: null,
-      local: null,
-      available: null,
-      tags: [...tags, "missing"],
-      missing: true,
-    };
-  }
-
-  const input = model.input.join("+") || "text";
-  const local = isLocalBaseUrl(model.baseUrl);
-  const available =
-    cfg && authStore
-      ? hasAuthForProvider(model.provider, cfg, authStore)
-      : (availableKeys?.has(modelKey(model.provider, model.id)) ?? false);
-  const aliasTags = aliases.length > 0 ? [`alias:${aliases.join(",")}`] : [];
-  const mergedTags = new Set(tags);
-  if (aliasTags.length > 0) {
-    for (const tag of mergedTags) {
-      if (tag === "alias" || tag.startsWith("alias:")) mergedTags.delete(tag);
-    }
-    for (const tag of aliasTags) mergedTags.add(tag);
-  }
-
-  return {
-    key,
-    name: model.name || model.id,
-    input,
-    contextWindow: model.contextWindow ?? null,
-    local,
-    available,
-    tags: Array.from(mergedTags),
-    missing: false,
-  };
-}
-
-function printModelTable(
-  rows: ModelRow[],
-  runtime: RuntimeEnv,
-  opts: { json?: boolean; plain?: boolean } = {},
-) {
-  if (opts.json) {
-    runtime.log(
-      JSON.stringify(
-        {
-          count: rows.length,
-          models: rows,
-        },
-        null,
-        2,
-      ),
-    );
-    return;
-  }
-
-  if (opts.plain) {
-    for (const row of rows) runtime.log(row.key);
-    return;
-  }
-
-  const rich = isRich(opts);
-  const header = [
-    pad("Model", MODEL_PAD),
-    pad("Input", INPUT_PAD),
-    pad("Ctx", CTX_PAD),
-    pad("Local", LOCAL_PAD),
-    pad("Auth", AUTH_PAD),
-    "Tags",
-  ].join(" ");
-  runtime.log(rich ? theme.heading(header) : header);
-
-  for (const row of rows) {
-    const keyLabel = pad(truncate(row.key, MODEL_PAD), MODEL_PAD);
-    const inputLabel = pad(row.input || "-", INPUT_PAD);
-    const ctxLabel = pad(formatTokenK(row.contextWindow), CTX_PAD);
-    const localText = row.local === null ? "-" : row.local ? "yes" : "no";
-    const localLabel = pad(localText, LOCAL_PAD);
-    const authText =
-      row.available === null ? "-" : row.available ? "yes" : "no";
-    const authLabel = pad(authText, AUTH_PAD);
-    const tagsLabel =
-      row.tags.length > 0
-        ? rich
-          ? row.tags.map((tag) => formatTag(tag, rich)).join(",")
-          : row.tags.join(",")
-        : "";
-
-    const coloredInput = colorize(
-      rich,
-      row.input.includes("image") ? theme.accentBright : theme.info,
-      inputLabel,
-    );
-    const coloredLocal = colorize(
-      rich,
-      row.local === null
-        ? theme.muted
-        : row.local
-          ? theme.success
-          : theme.muted,
-      localLabel,
-    );
-    const coloredAuth = colorize(
-      rich,
-      row.available === null
-        ? theme.muted
-        : row.available
-          ? theme.success
-          : theme.error,
-      authLabel,
-    );
-
-    const line = [
-      rich ? theme.accent(keyLabel) : keyLabel,
-      coloredInput,
-      ctxLabel,
-      coloredLocal,
-      coloredAuth,
-      tagsLabel,
-    ].join(" ");
-    runtime.log(line);
-  }
-}
